
theta1 = deg2rad(0); %[control:slider:090c]{"position":[18,19]}
theta2 = deg2rad(10); %[control:slider:0e33]{"position":[18,20]}
theta3 = deg2rad(10); %[control:slider:062c]{"position":[18,20]}
theta4 = deg2rad(-10); %[control:slider:97cf]{"position":[18,21]}

a1 = dh_link_to_transformation_matrix(0, 90, 0, theta1);
a2 = dh_link_to_transformation_matrix(0, 0, 0.150, theta2-pi/4);
a3 = dh_link_to_transformation_matrix(0, 0, 0.150, theta3-pi/4);
a4 = dh_link_to_transformation_matrix(0, 90, 0, theta4); % d4 might be something
T = a1 * a2 * a3 * a4 %[output:76beb558]

%[text] Let's now plot the origin and the location of the end effector in a top down view (XY plane) and a front view (XZ plane)
plot(0, 0, "bo", MarkerFaceColor="b") %[output:3c70f8d2]
hold on %[output:3c70f8d2]
plot(T(1,4), T(2,4), "ro", MarkerFaceColor="r") %[output:3c70f8d2]

hold off %[output:3c70f8d2]
title("Top down view (XY) plane") %[output:3c70f8d2]
legend("origin", "end effector") %[output:3c70f8d2]
xlim([-0.3 0.3]) %[output:3c70f8d2]
ylim([-0.3 0.3]) %[output:3c70f8d2]

% Plot the front view (XZ) plane
figure; %[output:0bcecc1f]
plot(0, 0, "bo", MarkerFaceColor="b") %[output:0bcecc1f]
hold on %[output:0bcecc1f]
plot(T(1,4), T(3,4), "ro", MarkerFaceColor="r") %[output:0bcecc1f]
hold off %[output:0bcecc1f]
title("Front view (XZ) plane") %[output:0bcecc1f]
legend("origin", "end effector") %[output:0bcecc1f]
xlim([-0.3 0.3]) %[output:0bcecc1f]
ylim([-0.3 0.3]) %[output:0bcecc1f]


